VALUES
  ('social-worker-moex-06080', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '協助服務使用者復原是社會工作重要功能之一。一位因受虐而不願意與他人互動的青少年被安置後，安 置機構為他安排參加了多次的治療團體，令他漸漸願意與別人接觸。這是下列那一種的復原功能？ 復健性復原功能  教育性復原功能  支持性復原功能  發展性復原功能', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b55fd4e38fe3", "answer_pdf_sha1": "e024a7c44cc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06081', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '一位社區工作者認為社區工作應以社區權力資源的再分配為目標，著重社區能力和網絡的建構、資源取 得、以及相互協商的行動，他/她使用下列那一種社區工作的模式？ 社區計畫模式  社會行動模式  社會目標模式  區域發展模式', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b55fd4e38fe3", "answer_pdf_sha1": "e024a7c44cc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06082', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作是一門專業，其建基於三類科學基礎之上。關於這三類的敘述，下列何者正確？①政治學知', '["社會學知識", "心理學知識", "已驗證的事實  ⑤假設性知識   ⑥設想的知識或實務知識", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b55fd4e38fe3", "answer_pdf_sha1": "e024a7c44cc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06083', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '後現代理論運用於社會工作實務，常見於受暴婦女的團體實務中。下列有關後現代社會工作實務之敘述，何 者錯誤？ 透過論述來建構知識，了解論述非固著、其意義會隨著情境、權勢、主觀位置的不同而有差異 透過敘說來連結自己和他人的經驗，發覺生活中的可能選項，察覺負面、傷害性的描述如何壓制和束 縛個人 重視個人的主體性，實務者應了解服務使用者多重且相互矛盾的角色認同 強調問題本身不是問題，個人本身才是問題，應將問題和人分開，開啟使用者的創造力與能量', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b55fd4e38fe3", "answer_pdf_sha1": "e024a7c44cc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06084', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '運用生態圖為工具描繪出個人與其所在環境交流的互動方向與關係強弱，是目前社會個案工作中必為的 程序之一，學理上稱之為生態評量（ecological assessment）。下列有關生態評量的敘述，何者錯誤？ 生態評量的重點是一方面評估個人需求所在，一方面呈現滿足需求的資源提供 實務操作步驟應涵括案主的重大生活壓力事件、性質及嚴重程度，相關重要他人對事件的看法與認知等 實務工作人員應與案主一起演繹、歸納和詮釋案主行為型態或其與環境交流的失衡原因，無需參採專 業知識架構 生態評量的資料蒐集來源包括語言、非口語反應、書寫、文件、與實務工作者的臨場觀察等', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b55fd4e38fe3", "answer_pdf_sha1": "e024a7c44cc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06085', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作理論各有強調的焦點領域，當中較多理論強調個人與社會關係。下列那一個理論並不聚焦於人 與社會的關係，而聚焦於個人的行動者特質？ 任務中心模式  危機調適模式  生態系統觀點  基變社會工作', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b55fd4e38fe3", "answer_pdf_sha1": "e024a7c44cc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06086', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '女性主義社會工作由女性主義的社會行動中產生，目標是透過連結女性個人的困境與其社會位置來重新 定義私領域的問題，使其成為公共議題。有關女性主義社會工作實務原則，下列何者錯誤？ 實務者應將女性的經驗當作問題分析的起點 實務者應敏感於女性的本質性啟發，創造一個可符應所有女性經驗的理論策略 實務者應關注並挑戰性別盲的理論觀點，避免將女性視為男性的衍生物 讓女性敘說自己的故事和談論自身經驗，是正確的知識蒐集方法', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b55fd4e38fe3", "answer_pdf_sha1": "e024a7c44cc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06087', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '強調看見案主身處的壓迫情境、追溯被壓迫團體的社會歷史、看見階級、種族、性別等歧視的交互作用，讓 人們管理、控制他們對需求和資源的定義。下列何者最符合此項定義的社會工作理論？ 基變社會工作  多元文化主義  增強權能理論  生態系統理論', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b55fd4e38fe3", "answer_pdf_sha1": "e024a7c44cc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06088', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關基變社會工作的理念與方法，下列敘述何者正確？ 受到馬克斯主義影響，認為社會工作是資本主義社會控制的媒介，但同時也會增強工人階級的力量 基變社會工作主張唯有不斷地提升實務者的專業化和專業地位，才能避免成為階級壓迫的幫兇 由於福利機構通常代表精英統治階級與意識形態，因此，為保有專業的獨立性，社會工作者應選擇自 行開業為佳 基變社會工作者應把意識覺醒、集體化、建立對話關係當作主要的技術，協助案主了解他們所處情境 之非常態化', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b55fd4e38fe3", "answer_pdf_sha1": "e024a7c44cc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06089', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '認知行為治療法（CBT）是一種思考人類功能和需求的方法，教導人如何在環境中運作，以最有效手段 達成個人目標的方法。下列有關CBT理論的敘述，何者錯誤？ 可略分為古典制約、操作制約、社會學習論三大支派 早期關注行為修正，後來偏重認知理論，晚近則強調建構主義；重視情緒處理，而非立即的認知或行 為改變 CBT主張干預策略之選擇應以高成功機率、適當的監督手段、創造練習機會、指定家庭作業等為主 CBT的治療環境不受時間限制、也無需與現實中的角色成就相連，當問題減輕時，即可結束治療', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b55fd4e38fe3", "answer_pdf_sha1": "e024a7c44cc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
